// app/courses/page.tsx
// This is a Server Component (no 'use client' = server by default)
// It runs ONLY on the server — the database query never ships to the browser

import { db } from '@/lib/database';

export default async function CoursesPage() {
  // Direct database access — possible because this runs on the server
  const courses = await db.query(
    'SELECT * FROM courses WHERE active = true ORDER BY created_at DESC'
  );

  return (
    <main>
      <h1>All Courses</h1>
      {courses.map(course => (
        <div key={course.id}>
          <h2>{course.title}</h2>
          <p>{course.description}</p>
          {/* This interactive button MUST be a Client Component */}
          <EnrollButton courseId={course.id} />
        </div>
      ))}
    </main>
  );
}

