from rest_framework import generics, permissions
from rest_framework.exceptions import PermissionDenied
from django_ratelimit.decorators import ratelimit
from django.utils.decorators import method_decorator

class OrderDetailView(generics.RetrieveUpdateAPIView):
    serializer_class = OrderSerializer
    permission_classes = [permissions.IsAuthenticated]

    def get_queryset(self):
        # BOLA prevention: ALWAYS filter by the requesting user
        # Even if someone passes ?id=another_users_order, this query
        # will return nothing instead of that order
        return Order.objects.filter(
            user=self.request.user,   # ← this one line prevents BOLA
            is_deleted=False
        )

    def get_serializer_class(self):
        # Return different serializer for different roles
        # Admin gets full data, regular users get limited fields
        if self.request.user.is_staff:
            return AdminOrderSerializer
        return CustomerOrderSerializer  # excludes internal fields

